  ('real-estate-moex-02439', 'real-estate', 'real-estate-moex-098-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地所有權人依土地法所申報之地價稱為：', '["法定地價", "公告現值", "標準地價", "公告地價"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "5b4bb6021937", "answer_pdf_sha1": "74a47bf57aaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
