  ('real-estate-moex-02441', 'real-estate', 'real-estate-moex-098-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依土地稅法規定，有關地價稅優惠稅率與減免，下列何者正確？', '["已辦妥寺廟登記之寺廟，按千分之十計徵地價稅", "依法核定之工業區土地按千分之六優惠稅率計徵地價稅", "都市計畫公共設施保留地，在保留期間仍為建築使用者，統按千分之二計徵地價稅", "經目的事業主管機關核准設立之私立公園、體育場所使用範圍內之土地，免徵地價稅"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "5b4bb6021937", "answer_pdf_sha1": "74a47bf57aaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
